import{_ as t,c as r,a0 as i,o as l}from"./chunks/framework.B6JXc2q-.js";const _=JSON.parse('{"title":"认证恢复入口统一约束规范","description":"","frontmatter":{},"headers":[],"relativePath":"spec/auth_recovery_entrypoint_unification.md","filePath":"spec/auth_recovery_entrypoint_unification.md"}'),o={name:"spec/auth_recovery_entrypoint_unification.md"};function a(d,e,c,s,n,h){return l(),r("div",null,e[0]||(e[0]=[i('<h1 id="认证恢复入口统一约束规范" tabindex="-1">认证恢复入口统一约束规范 <a class="header-anchor" href="#认证恢复入口统一约束规范" aria-label="Permalink to &quot;认证恢复入口统一约束规范&quot;">​</a></h1><p>版本：v1.0 状态：1.0.9 修复约束文档 最后更新：2026-03-29 适用范围：<code>xiaomusic/auth.py</code> 内所有会触发 clear+rebuild / relogin / redirect 的路径</p><hr><h2 id="_1-文档目的" tabindex="-1">1. 文档目的 <a class="header-anchor" href="#_1-文档目的" aria-label="Permalink to &quot;1. 文档目的&quot;">​</a></h2><p>本文档用于解决&quot;恢复入口分裂导致 singleflight 覆盖不完整&quot;的问题。</p><ul><li>服务于 1.0.9 的最小侵入修复</li><li>是对 <code>docs/spec/auth_recovery_state_machine.md</code> 和 <code>docs/spec/auth_recovery_singleflight.md</code> 的补充</li><li>只新增&quot;恢复入口统一与执行权收口&quot;的行为约束层</li></ul><hr><h2 id="_2-问题背景" tabindex="-1">2. 问题背景 <a class="header-anchor" href="#_2-问题背景" aria-label="Permalink to &quot;2. 问题背景&quot;">​</a></h2><p>当前 <code>auth_call</code> 内部已经具备 leader/follower/backoff 机制。</p><p>但系统中仍存在多个绕过 <code>auth_call</code> 的恢复路径，这些路径会直接触发：</p><ul><li><code>_clear_short_lived_session()</code></li><li><code>_rebuild_short_session_from_persistent_auth()</code></li><li><code>rebuild_services()</code></li><li><code>ensure_logged_in(prefer_refresh=True)</code></li></ul><p>结果是系统级别仍可能出现多个并发 rebuild / redirect。</p><hr><h2 id="_3-术语定义" tabindex="-1">3. 术语定义 <a class="header-anchor" href="#_3-术语定义" aria-label="Permalink to &quot;3. 术语定义&quot;">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>定义</th></tr></thead><tbody><tr><td>触发入口（trigger entrypoint）</td><td>检测到认证异常并发出恢复请求的路径</td></tr><tr><td>恢复执行入口（recovery execution entrypoint）</td><td>实际执行 clear / rebuild / relogin 的代码路径</td></tr><tr><td>恢复执行权（recovery execution authority）</td><td>独占执行恢复动作的权利，同一时间只应有一个持有者</td></tr><tr><td>clear+rebuild</td><td>clear short session + rebuild short session + runtime rebind 的组合</td></tr><tr><td>relogin / redirect</td><td>通过 persistent-auth 或 refresh 重建会话，可能触发云端请求</td></tr><tr><td>singleflight 保护层</td><td>leader/follower/backoff 机制，确保恢复执行权互斥</td></tr><tr><td>最小侵入修复</td><td>不做大重构，只统一收口恢复执行入口</td></tr></tbody></table><hr><h2 id="_4-当前实现中的恢复入口分类" tabindex="-1">4. 当前实现中的恢复入口分类 <a class="header-anchor" href="#_4-当前实现中的恢复入口分类" aria-label="Permalink to &quot;4. 当前实现中的恢复入口分类&quot;">​</a></h2><h3 id="_4-1-触发侧入口-trigger-side" tabindex="-1">4.1 触发侧入口（trigger side） <a class="header-anchor" href="#_4-1-触发侧入口-trigger-side" aria-label="Permalink to &quot;4.1 触发侧入口（trigger side）&quot;">​</a></h3><p>这些入口可以检测认证异常并发出恢复需求，但不应直接拥有恢复执行权：</p><table tabindex="0"><thead><tr><th>入口</th><th>触发方式</th></tr></thead><tbody><tr><td><code>auth_call</code></td><td>检测到 auth error 后进入 suspect / clear+rebuild 流程</td></tr><tr><td><code>keepalive_loop</code></td><td>keepalive 常规失败后调用 <code>ensure_logged_in</code></td></tr><tr><td><code>keepalive_auto_recover</code></td><td>keepalive 连续失败后自动调用 <code>ensure_logged_in(prefer_refresh=True)</code></td></tr><tr><td><code>keepalive_proactive_recovery</code></td><td>keepalive 进入 degraded 后主动调用 <code>ensure_logged_in(prefer_refresh=True)</code></td></tr><tr><td><code>init_all_data</code></td><td>检测 short session 缺失后调用 <code>_rebuild_short_session_from_persistent_auth</code></td></tr><tr><td><code>init_all_data_verify_failed</code></td><td>init 登录失败后执行 clear + rebuild</td></tr><tr><td><code>getalldevices</code> / 设备初始化路径</td><td>初始化时可能触发登录或恢复流程</td></tr></tbody></table><h3 id="_4-2-恢复执行动作-recovery-execution-actions" tabindex="-1">4.2 恢复执行动作（recovery execution actions） <a class="header-anchor" href="#_4-2-恢复执行动作-recovery-execution-actions" aria-label="Permalink to &quot;4.2 恢复执行动作（recovery execution actions）&quot;">​</a></h3><p>这些动作真正会改变认证状态或触发云端重建：</p><table tabindex="0"><thead><tr><th>动作</th><th>说明</th></tr></thead><tbody><tr><td><code>_clear_short_lived_session()</code></td><td>清除 short session（runtime 注入态 + auth.json）</td></tr><tr><td><code>_rebuild_short_session_from_persistent_auth()</code></td><td>从长期态重建短期态</td></tr><tr><td><code>_rebuild_short_session_tokens_from_persistent_auth()</code></td><td>重建 short session tokens</td></tr><tr><td><code>_rebuild_service_cookies_from_persistent_auth()</code></td><td>重建 service cookies</td></tr><tr><td><code>rebuild_services()</code></td><td>重新初始化 mina_service / miio_service</td></tr><tr><td><code>ensure_logged_in(prefer_refresh=True)</code></td><td>完整的 clear + rebuild + rebind + verify 链</td></tr></tbody></table><p><strong>关键区分</strong>：&quot;触发恢复&quot;与&quot;执行恢复&quot;不是同一个层次。</p><hr><h2 id="_5-当前问题的根因归纳" tabindex="-1">5. 当前问题的根因归纳 <a class="header-anchor" href="#_5-当前问题的根因归纳" aria-label="Permalink to &quot;5. 当前问题的根因归纳&quot;">​</a></h2><ul><li>singleflight 当前挂在 <code>auth_call</code> 路径，而不是挂在&quot;恢复执行权&quot;这一层</li><li>因此 <code>auth_call</code> 外的恢复路径仍可直接进入 rebuild / relogin</li><li>这会导致系统级别仍可能存在多个 redirect / rebuild</li><li><strong>当前问题的根因是&quot;恢复入口统一失败&quot;，不是&quot;singleflight 机制无效&quot;</strong></li></ul><hr><h2 id="_6-1-0-9-的最小修复目标" tabindex="-1">6. 1.0.9 的最小修复目标 <a class="header-anchor" href="#_6-1-0-9-的最小修复目标" aria-label="Permalink to &quot;6. 1.0.9 的最小修复目标&quot;">​</a></h2><p>1.0.9 不做完整协调器拆分，不做大规模重构，不做已有状态机语义改变。</p><p>本次只做一件事：</p><p><strong>凡是会触发 clear+rebuild / relogin / redirect 的路径，都必须经过同一个受 singleflight 保护的执行入口。</strong></p><hr><h2 id="_7-本次修复的统一约束" tabindex="-1">7. 本次修复的统一约束 <a class="header-anchor" href="#_7-本次修复的统一约束" aria-label="Permalink to &quot;7. 本次修复的统一约束&quot;">​</a></h2><h3 id="_7-1-触发路径约束" tabindex="-1">7.1 触发路径约束 <a class="header-anchor" href="#_7-1-触发路径约束" aria-label="Permalink to &quot;7.1 触发路径约束&quot;">​</a></h3><table tabindex="0"><thead><tr><th>路径</th><th>允许做的事</th><th>不允许做的事</th></tr></thead><tbody><tr><td><code>keepalive</code></td><td>触发恢复请求</td><td>直接绕过统一入口执行 clear+rebuild</td></tr><tr><td><code>init_all_data</code></td><td>识别 short session 缺失</td><td>直接独占执行 rebuild 主链</td></tr><tr><td><code>getalldevices</code> / 初始化路径</td><td>发出恢复需求</td><td>直接并发触发 persistent-auth relogin</td></tr></tbody></table><h3 id="_7-2-恢复执行权约束" tabindex="-1">7.2 恢复执行权约束 <a class="header-anchor" href="#_7-2-恢复执行权约束" aria-label="Permalink to &quot;7.2 恢复执行权约束&quot;">​</a></h3><ul><li>singleflight 应保护的是&quot;恢复执行权&quot;，而不只是 <code>auth_call</code> 某个调用点</li><li>任何会触发 redirect / relogin / clear short session 的路径，都必须统一进入 singleflight 保护层</li><li>leader 独占恢复执行权，follower 等待 leader 完成，backoff 阻断失败后立即重入</li></ul><h3 id="_7-3-绝对约束" tabindex="-1">7.3 绝对约束 <a class="header-anchor" href="#_7-3-绝对约束" aria-label="Permalink to &quot;7.3 绝对约束&quot;">​</a></h3><ul><li>follower 不 clear</li><li>follower 不 rebuild</li><li>leader 独占恢复主链</li><li>失败后有 backoff</li></ul><hr><h2 id="_8-建议的最小实现方向" tabindex="-1">8. 建议的最小实现方向 <a class="header-anchor" href="#_8-建议的最小实现方向" aria-label="Permalink to &quot;8. 建议的最小实现方向&quot;">​</a></h2><h3 id="_8-1-方向说明" tabindex="-1">8.1 方向说明 <a class="header-anchor" href="#_8-1-方向说明" aria-label="Permalink to &quot;8.1 方向说明&quot;">​</a></h3><ul><li>后续应抽出一个统一的内部恢复执行入口</li><li>各触发路径改为调用这个统一入口，而不是直接执行 rebuild</li><li><code>auth_call</code> 保留现有状态机语义，但恢复执行最终应落到统一入口</li><li>keepalive / init_all_data 的最小改动目标是&quot;接入统一入口&quot;，不是各自复制 singleflight 逻辑</li><li>在现有实现里，<code>ensure_logged_in(prefer_refresh=True)</code> 所承载的是最接近&quot;恢复执行主链&quot;的行为边界；后续最小改动应优先让会进入 clear+rebuild / relogin / redirect 的路径统一落到受保护入口，而不是给每个底层 rebuild 动作分别复制 singleflight</li></ul><h3 id="_8-2-不展开的内容" tabindex="-1">8.2 不展开的内容 <a class="header-anchor" href="#_8-2-不展开的内容" aria-label="Permalink to &quot;8.2 不展开的内容&quot;">​</a></h3><ul><li>不设计完整协调器类</li><li>不设计大规模模块拆分</li><li>不改变 Phase A / strong evidence / suspect 的语义</li></ul><hr><h2 id="_9-明确不在本次范围内的事项" tabindex="-1">9. 明确不在本次范围内的事项 <a class="header-anchor" href="#_9-明确不在本次范围内的事项" aria-label="Permalink to &quot;9. 明确不在本次范围内的事项&quot;">​</a></h2><p>本次不做：</p><ul><li>不拆分完整 <code>AuthRecoveryCoordinator</code></li><li>不重写 <code>auth_call</code></li><li>不重写 <code>ensure_logged_in</code> 全部职责</li><li>不改变 Phase A / strong evidence / suspect 状态机定义</li><li>不引入新的恢复策略分支</li><li>不做大规模模块重构</li></ul><hr><h2 id="_10-与现有文档的关系" tabindex="-1">10. 与现有文档的关系 <a class="header-anchor" href="#_10-与现有文档的关系" aria-label="Permalink to &quot;10. 与现有文档的关系&quot;">​</a></h2><ul><li>本文档补充 <code>docs/spec/auth_recovery_state_machine.md</code></li><li>本文档补充 <code>docs/spec/auth_recovery_singleflight.md</code></li><li>状态机语义仍以前两者为准</li><li>本文档只新增&quot;恢复入口统一与执行权收口&quot;的行为约束层</li></ul><hr><h2 id="_11-验收标准" tabindex="-1">11. 验收标准 <a class="header-anchor" href="#_11-验收标准" aria-label="Permalink to &quot;11. 验收标准&quot;">​</a></h2><p>文档完成后，应能支持维护者准确回答：</p><ol><li><p><strong>为什么 <code>auth_call</code> 已有 leader，但系统仍然出现多次 redirect？</strong> 因为 singleflight 只挂在 <code>auth_call</code> 路径，keepalive / init_all_data 等路径绕过了它。</p></li><li><p><strong>哪些路径只是触发恢复，不应直接执行恢复？</strong> keepalive、init_all_data、getalldevices 等触发侧入口。</p></li><li><p><strong>为什么 singleflight 应保护&quot;恢复执行权&quot;而不是只保护 <code>auth_call</code>？</strong> 因为恢复执行动作（clear / rebuild / relogin）可能从多个入口触发，singleflight 必须保护这些动作的互斥执行。</p></li><li><p><strong>1.0.9 本次修复为什么是&quot;统一入口&quot;而不是&quot;大重构&quot;？</strong> 因为当前问题根因是入口分裂，不是架构缺陷；统一入口是最小侵入的有效修复。</p></li><li><p><strong>后续最小改动时，哪些行为绝不能被破坏？</strong></p><ul><li>follower 不 clear、不 rebuild</li><li>leader 独占恢复主链</li><li>失败后有 backoff</li><li>suspect / Phase A / strong evidence 语义不变</li></ul></li><li><p><strong>后续实现时，对新增路径有什么约束？</strong></p><ul><li>任何新增会触发 clear+rebuild / relogin / redirect 的路径，都必须遵守本文档的统一入口约束</li><li>不得新增绕过统一恢复执行入口的新恢复路径</li></ul></li></ol>',57)]))}const b=t(o,[["render",a]]);export{_ as __pageData,b as default};
